import {useState, useEffect} from 'react'
import {ethers} from 'ethers'
import abis from '../utils/abis'
import {Button} from 'react-bootstrap'

const OracleSwitchV3 = ({web3, nn}) => {
    const oracles = {
        wooBTCUSD: '0x1cB5952f1Dad5F287B064A56b76Ea4f499e13891',
        wooETHUSD: '0x41794F96A87A36ff4896183C2c16e8522101243c',
        wooBNBUSD: '0x3E83C50b1Bf719a8eCF41b19aa64185D1E1d4e9a',
        chainlinkBTCUSD: '0x5D5b670Fe243CF172A25C826977923cD57381160',
        chainlinkETHUSD: '0x34f532C7224297bA42A184F63Ce5eB3322212e48',
        chainlinkBNBUSD: '0x48315bE7b14a38e8Eb0E5191F67Ba4cd721b0F51',
    }
    const oracleManager = new web3.eth.Contract(abis.OracleManager, '0xAB4A3348B92Ac3Bd668DB7201088071CB65A0316')
    const signer = '0x6E72d826fDA933FAb33C10D2E91716216Ddeb13B'
    const [activeOracles, setActiveOracles] = useState({})
    const [prices, setPrices] = useState({})

    useEffect(() => {(async () => {
        const newActiveOracles = await getActiveOracles()
        const newPrices = await getPrices()
        setActiveOracles({...activeOracles, ...newActiveOracles})
        setPrices({...prices, ...newPrices})
    })()})

    const getActiveOracles = async () => {
        const newActiveOracles = {}
        const symbols = ['BTCUSD', 'ETHUSD', 'BNBUSD']
        for (const symbol of symbols) {
            newActiveOracles[symbol] = await oracleManager.methods['getOracle(string)'](symbol).call()
        }
        return newActiveOracles
    }

    const getPrices = async () => {
        const newPrices = {}
        for (const [name, address] of Object.entries(oracles)) {
            const contract = new web3.eth.Contract(abis.OracleV3, address)
            newPrices[name] = await contract.methods.value().call()
        }
        const symbols = ['BTCUSD', 'ETHUSD', 'BNBUSD']
        for (const symbol of symbols) {
            newPrices[symbol] = await oracleManager.methods.value(ethers.utils.id(symbol)).call()
        }
        return newPrices
    }

    const switchOracle = async (symbol) => {
        const target = activeOracles[symbol] === oracles[`woo${symbol}`] ? oracles[`chainlink${symbol}`] : oracles[`woo${symbol}`]
        console.log(target)
        await oracleManager.methods.setOracle(target).send({from: signer})
        const newActiveOracles = await getActiveOracles()
        const newPrices = await getPrices()
        setActiveOracles({...activeOracles, ...newActiveOracles})
        setPrices({...prices, ...newPrices})
    }

    return (
        <div>
            <br/>
            <h5>Deri V3 Oracle Switch (BSC)</h5>
            <p><b>Signer: </b>{signer}</p>
            <table>
            <tbody>
                <tr>
                    <th></th>
                    <th>WooTrade</th>
                    <th></th>
                    <th>Chainlink</th>
                    <th></th>
                    <th></th>
                </tr>
                <tr>
                    <th>BTCUSD</th>
                    <td bgcolor={activeOracles.BTCUSD === oracles.wooBTCUSD ? 'lightgreen' : ''}>{oracles.wooBTCUSD}</td>
                    <td bgcolor={prices.BTCUSD === prices.wooBTCUSD ? 'lightgreen' : ''}>{nn(prices.wooBTCUSD)}</td>
                    <td bgcolor={activeOracles.BTCUSD === oracles.chainlinkBTCUSD ? 'lightgreen' : ''}>{oracles.chainlinkBTCUSD}</td>
                    <td bgcolor={prices.BTCUSD === prices.chainlinkBTCUSD ? 'lightgreen' : ''}>{nn(prices.chainlinkBTCUSD)}</td>
                    <td><Button onClick={() => switchOracle('BTCUSD')}>Switch to {activeOracles.BTCUSD === oracles.wooBTCUSD ? 'Chainlink' : 'WooTrade'}</Button></td>
                </tr>
                <tr>
                    <th>ETHUSD</th>
                    <td bgcolor={activeOracles.ETHUSD === oracles.wooETHUSD ? 'lightgreen' : ''}>{oracles.wooETHUSD}</td>
                    <td bgcolor={prices.ETHUSD === prices.wooETHUSD ? 'lightgreen' : ''}>{nn(prices.wooETHUSD)}</td>
                    <td bgcolor={activeOracles.ETHUSD === oracles.chainlinkETHUSD ? 'lightgreen' : ''}>{oracles.chainlinkETHUSD}</td>
                    <td bgcolor={prices.ETHUSD === prices.chainlinkETHUSD ? 'lightgreen' : ''}>{nn(prices.chainlinkETHUSD)}</td>
                    <td><Button onClick={() => switchOracle('ETHUSD')}>Switch to {activeOracles.ETHUSD === oracles.wooETHUSD ? 'Chainlink' : 'WooTrade'}</Button></td>
                </tr>
                <tr>
                    <th>BNBUSD</th>
                    <td bgcolor={activeOracles.BNBUSD === oracles.wooBNBUSD ? 'lightgreen' : ''}>{oracles.wooBNBUSD}</td>
                    <td bgcolor={prices.BNBUSD === prices.wooBNBUSD ? 'lightgreen' : ''}>{nn(prices.wooBNBUSD)}</td>
                    <td bgcolor={activeOracles.BNBUSD === oracles.chainlinkBNBUSD ? 'lightgreen' : ''}>{oracles.chainlinkBNBUSD}</td>
                    <td bgcolor={prices.BNBUSD === prices.chainlinkBNBUSD ? 'lightgreen' : ''}>{nn(prices.chainlinkBNBUSD)}</td>
                    <td><Button onClick={() => switchOracle('BNBUSD')}>Switch to {activeOracles.BNBUSD === oracles.wooBNBUSD ? 'Chainlink' : 'WooTrade'}</Button></td>
                </tr>
            </tbody>
            </table>
        </div>
    )
}

export default OracleSwitchV3
